     1→const express = require('express');
     2→const bcrypt = require('bcryptjs');
     3→const crypto = require('crypto');
     4→const router = express.Router();
     5→
     6→let logAuthEvent;
     7→try {
     8→  logAuthEvent = require('../lib/activity-logger').logAuthEvent;
     9→} catch (e) {
    10→  logAuthEvent = () => {}; // Fallback no-op
    11→}
    12→
    13→// ─── Rate Limiting (in-memory) ──────────────────────────────────────────────
    14→const loginAttempts = new Map(); // ip -> { count, firstAttempt }
    15→const RATE_LIMIT_WINDOW = 15 * 60 * 1000; // 15 minutes
    16→const MAX_ATTEMPTS = 5;
    17→
    18→function checkRateLimit(ip) {
    19→  const now = Date.now();
    20→  const record = loginAttempts.get(ip);
    21→
    22→  if (!record || (now - record.firstAttempt) > RATE_LIMIT_WINDOW) {
    23→    loginAttempts.set(ip, { count: 1, firstAttempt: now });
    24→    return { allowed: true, remaining: MAX_ATTEMPTS - 1 };
    25→  }
    26→
    27→  if (record.count >= MAX_ATTEMPTS) {
    28→    const retryAfter = Math.ceil((RATE_LIMIT_WINDOW - (now - record.firstAttempt)) / 1000);
    29→    return { allowed: false, retryAfter };
    30→  }
    31→
    32→  record.count++;
    33→  return { allowed: true, remaining: MAX_ATTEMPTS - record.count };
    34→}
    35→
    36→// Clean up old rate limit entries every 30 minutes
    37→setInterval(() => {
    38→  const now = Date.now();
    39→  for (const [ip, record] of loginAttempts.entries()) {
    40→    if ((now - record.firstAttempt) > RATE_LIMIT_WINDOW) {
    41→      loginAttempts.delete(ip);
    42→    }
    43→  }
    44→}, 30 * 60 * 1000);
    45→
    46→// ─── Admin Credentials ─────────────────────────────────────────────────────
    47→// Generate a default password if not set in env
    48→let ADMIN_PASSWORD_HASH = null;
    49→const ADMIN_USERNAME = process.env.ADMIN_USERNAME || 'admin';
    50→
    51→async function initAdminCredentials() {
    52→  const password = process.env.ADMIN_PASSWORD;
    53→
    54→  if (password) {
    55→    ADMIN_PASSWORD_HASH = await bcrypt.hash(password, 12);
    56→    console.log('[admin] Admin credentials loaded from env vars');
    57→  } else {
    58→    // Generate a strong default password
    59→    const defaultPassword = crypto.randomBytes(16).toString('base64url');
    60→    ADMIN_PASSWORD_HASH = await bcrypt.hash(defaultPassword, 12);
    61→    console.log('');
    62→    console.log('╔══════════════════════════════════════════════════════════════╗');
    63→    console.log('║                    ADMIN CREDENTIALS                         ║');
    64→    console.log('╠══════════════════════════════════════════════════════════════╣');
    65→    console.log(`║  Username: ${ADMIN_USERNAME.padEnd(48)}║`);
    66→    console.log(`║  Password: ${defaultPassword.padEnd(48)}║`);
    67→    console.log('║                                                              ║');
    68→    console.log('║  Set ADMIN_PASSWORD env var to use your own password.        ║');
    69→    console.log('╚══════════════════════════════════════════════════════════════╝');
    70→    console.log('');
    71→  }
    72→}
    73→
    74→// Initialize on module load
    75→initAdminCredentials();
    76→
    77→// ─── Middleware ──────────────────────────────────────────────────────────────
    78→function requireAdmin(req, res, next) {
    79→  if (req.session && req.session.isAdmin) {
    80→    return next();
    81→  }
    82→  return res.status(401).json({ error: 'Admin authentication required' });
    83→}
    84→
    85→// ─── Routes ─────────────────────────────────────────────────────────────────
    86→
    87→// POST /api/admin/login
    88→router.post('/login', async (req, res) => {
    89→  const ip = req.ip || req.connection.remoteAddress || 'unknown';
    90→  const rateCheck = checkRateLimit(ip);
    91→
    92→  if (!rateCheck.allowed) {
    93→    return res.status(429).json({
    94→      error: 'Too many login attempts',
    95→      retryAfter: rateCheck.retryAfter,
    96→      message: `Too many failed login attempts. Try again in ${Math.ceil(rateCheck.retryAfter / 60)} minutes.`,
    97→    });
    98→  }
    99→
   100→  const { username, password } = req.body;
   101→
   102→  if (!username || !password) {
   103→    return res.status(400).json({ error: 'Username and password required' });
   104→  }
   105→
   106→  // Wait for hash to be ready
   107→  if (!ADMIN_PASSWORD_HASH) {
   108→    return res.status(503).json({ error: 'Server initializing, try again in a moment' });
   109→  }
   110→
   111→  const usernameMatch = username === ADMIN_USERNAME;
   112→  const passwordMatch = await bcrypt.compare(password, ADMIN_PASSWORD_HASH);
   113→
   114→  if (!usernameMatch || !passwordMatch) {
   115→    logAuthEvent('admin_login_failed', null, username, ip, { reason: 'invalid_credentials' });
