   117→  }
   118→
   119→  // Set admin session
   120→  req.session.isAdmin = true;
   121→  req.session.adminLoginAt = new Date().toISOString();
   122→
   123→  // Reset rate limiter on success
   124→  loginAttempts.delete(ip);
   125→
   126→  logAuthEvent('admin_login_success', null, ADMIN_USERNAME, ip);
   127→
   128→  return res.json({
   129→    success: true,
   130→    message: 'Admin login successful',
   131→    user: { username: ADMIN_USERNAME, role: 'admin' },
   132→  });
   133→});
   134→
   135→// GET /api/admin/me
