   138→    return res.json({
   139→      authenticated: true,
   140→      user: {
   141→        username: ADMIN_USERNAME,
   142→        role: 'admin',
   143→        loginAt: req.session.adminLoginAt,
   144→      },
   145→    });
   146→  }
   147→  return res.status(401).json({ authenticated: false });
   148→});
