     1→/**
     2→ * OpenAI Token Budget Service
     3→ *
     4→ * Tracks OpenAI token usage across all modalities (LLM, TTS, ASR, Vision, Embedding).
     5→ * When daily budget (100K tokens) is exhausted, signals the AI provider to skip OpenAI
     6→ * and route directly to NIM providers.
     7→ *
     8→ * Token estimation:
     9→ * - LLM: uses response.usage.total_tokens when available, estimates from text length otherwise
    10→ * - TTS: ~1 token per 4 characters of input text
    11→ * - ASR: ~1 token per second of audio (Whisper pricing model)
    12→ * - Vision: ~85 tokens per image + prompt tokens
    13→ * - Embedding: ~1 token per 4 characters
    14→ */
    15→
    16→const DAILY_BUDGET = parseInt(process.env.OPENAI_DAILY_TOKEN_BUDGET, 10) || 100000;
    17→
    18→class TokenBudgetService {
    19→  constructor() {
    20→    this.dailyBudget = DAILY_BUDGET;
    21→    this.tokensUsed = 0;
    22→    this.budgetExhausted = false;
    23→    this.currentDay = this._getUTCDay();
    24→    this.history = [];         // Last 7 days of usage
    25→    this.modalityBreakdown = { // Per-modality tracking
    26→      llm: 0,
    27→      tts: 0,
    28→      asr: 0,
    29→      vision: 0,
    30→      embedding: 0,
    31→      other: 0,
    32→    };
    33→    this.exhaustedAt = null;   // Timestamp when budget was exhausted
    34→    this.resetAt = null;       // Next reset time
    35→
    36→    this._updateResetTime();
    37→    this._startMidnightReset();
    38→
    39→    console.log(`[token-budget] Initialized. Daily budget: ${this.dailyBudget.toLocaleString()} tokens`);
    40→  }
    41→
