/**
 * Metrics Collector — Comprehensive infrastructure monitoring.
 *
 * Collects: server metrics (CPU, memory, uptime), database metrics,
 * API metrics (request counts, error rates, latency percentiles),
 * user/interview session metrics.
 *
 * Exposed via /api/admin/metrics endpoint.
 */

const os = require('os');
const pool = require('./db');
const { SERVER_START_TIME } = require('./activity-logger');

// ─── Request Metrics (in-memory, rolling window) ───────────────
const REQUEST_WINDOW_MS = 60 * 60 * 1000; // 1 hour rolling window

class RequestMetrics {
  constructor() {
    this.requests = [];       // { timestamp, method, path, status, duration }
    this.totalRequests = 0;
    this.totalErrors = 0;
    this.endpointCounts = {};  // { path: { total, errors, durations[] } }
  }

  record(method, path, status, duration) {
    const now = Date.now();
    this.requests.push({ timestamp: now, method, path, status, duration });
    this.totalRequests++;
    if (status >= 400) this.totalErrors++;

    // Per-endpoint tracking
    const key = `${method} ${path}`;
    if (!this.endpointCounts[key]) {
      this.endpointCounts[key] = { total: 0, errors: 0, durations: [] };
    }
    this.endpointCounts[key].total++;
    if (status >= 400) this.endpointCounts[key].errors++;
    this.endpointCounts[key].durations.push(duration);

    // Keep only last 1000 durations per endpoint
    if (this.endpointCounts[key].durations.length > 1000) {
      this.endpointCounts[key].durations = this.endpointCounts[key].durations.slice(-500);
    }

    // Prune old entries every 100 requests
    if (this.requests.length % 100 === 0) {
      this._prune(now);
    }
  }

  _prune(now) {
    const cutoff = now - REQUEST_WINDOW_MS;
    this.requests = this.requests.filter(r => r.timestamp >= cutoff);
  }

  getPercentile(durations, pct) {
    if (durations.length === 0) return 0;
    const sorted = [...durations].sort((a, b) => a - b);
    const idx = Math.ceil((pct / 100) * sorted.length) - 1;
    return sorted[Math.max(0, idx)];
  }

  getSummary() {
    const now = Date.now();
    this._prune(now);

    // Requests in last hour
    const recentRequests = this.requests;
    const recentErrors = recentRequests.filter(r => r.status >= 400);
    const durations = recentRequests.map(r => r.duration).filter(d => d != null);

    // Top endpoints by traffic
    const topEndpoints = Object.entries(this.endpointCounts)
      .map(([path, data]) => ({
        path,
        total: data.total,
        errors: data.errors,
        errorRate: data.total > 0 ? ((data.errors / data.total) * 100).toFixed(1) : '0.0',
        p50: this.getPercentile(data.durations, 50),
        p95: this.getPercentile(data.durations, 95),
        p99: this.getPercentile(data.durations, 99),
      }))
      .sort((a, b) => b.total - a.total)
      .slice(0, 20);

    return {
      hourly: {
        requests: recentRequests.length,
        errors: recentErrors.length,
        errorRate: recentRequests.length > 0
          ? ((recentErrors.length / recentRequests.length) * 100).toFixed(1)
          : '0.0',
      },
      cumulative: {
        totalRequests: this.totalRequests,
        totalErrors: this.totalErrors,
        errorRate: this.totalRequests > 0
          ? ((this.totalErrors / this.totalRequests) * 100).toFixed(1)
          : '0.0',
      },
      latency: {
        p50: this.getPercentile(durations, 50),
        p95: this.getPercentile(durations, 95),
        p99: this.getPercentile(durations, 99),
        avg: durations.length > 0 ? Math.round(durations.reduce((a, b) => a + b, 0) / durations.length) : 0,
      },
      topEndpoints,
    };
  }
}

const requestMetrics = new RequestMetrics();

// ─── Metrics Collection Functions ─────────────────────────────

/**
 * Get server metrics (CPU, memory, uptime).
 */
function getServerMetrics() {
  const uptime = Math.floor((Date.now() - SERVER_START_TIME) / 1000);
  const memUsage = process.memoryUsage();
  const totalMem = os.totalmem();
  const freeMem = os.freemem();
  const cpus = os.cpus();

  // Calculate CPU usage from cpus
  let totalIdle = 0;
  let totalTick = 0;
  for (const cpu of cpus) {
    for (const type of Object.keys(cpu.times)) {
      totalTick += cpu.times[type];
    }
    totalIdle += cpu.times.idle;
  }
  const cpuUsage = ((1 - totalIdle / totalTick) * 100).toFixed(1);

  return {
    uptime,
    uptimeFormatted: formatUptime(uptime),
    cpu: {
      usage: parseFloat(cpuUsage),
      cores: cpus.length,
      model: cpus[0]?.model || 'unknown',
    },
    memory: {
      heapUsed: memUsage.heapUsed,
      heapTotal: memUsage.heapTotal,
      rss: memUsage.rss,
      external: memUsage.external,
      heapUsedMB: Math.round(memUsage.heapUsed / 1024 / 1024),
      rssMB: Math.round(memUsage.rss / 1024 / 1024),
      systemTotal: totalMem,
      systemFree: freeMem,
      systemUsedPct: ((1 - freeMem / totalMem) * 100).toFixed(1),
    },
    platform: {
      node: process.version,
      os: `${os.type()} ${os.release()}`,
      arch: os.arch(),
      hostname: os.hostname(),
    },
  };
}

function formatUptime(seconds) {
  const days = Math.floor(seconds / 86400);
  const hours = Math.floor((seconds % 86400) / 3600);
  const minutes = Math.floor((seconds % 3600) / 60);
  if (days > 0) return `${days}d ${hours}h ${minutes}m`;
  if (hours > 0) return `${hours}h ${minutes}m`;
  return `${minutes}m`;
}

/**
 * Get database metrics.
 */
async function getDatabaseMetrics() {
  try {
    const [sizeResult, connResult, tableResult] = await Promise.all([
      pool.query("SELECT pg_database_size(current_database()) as size"),
      pool.query("SELECT count(*) as count FROM pg_stat_activity WHERE state = 'active'"),
      pool.query(`
        SELECT relname as table_name, n_live_tup as row_count
        FROM pg_stat_user_tables
        ORDER BY n_live_tup DESC
        LIMIT 15
      `),
    ]);

    const dbSizeBytes = parseInt(sizeResult.rows[0]?.size || 0, 10);
    const activeConns = parseInt(connResult.rows[0]?.count || 0, 10);

    return {
      sizeBytes: dbSizeBytes,
      sizeMB: (dbSizeBytes / 1024 / 1024).toFixed(1),
      activeConnections: activeConns,
      poolTotal: pool.totalCount || 0,
      poolIdle: pool.idleCount || 0,
      poolWaiting: pool.waitingCount || 0,
      tables: tableResult.rows.map(r => ({
        name: r.table_name,
        rows: parseInt(r.row_count, 10),
      })),
    };
  } catch (err) {
    console.error('[metrics] Database metrics error:', err.message);
    return { error: err.message };
  }
}

/**
 * Get user and interview metrics.
 */
async function getUserMetrics() {
  try {
    const [
      usersResult,
      activeResult,
      interviewsResult,
      interviewsTodayResult,
    ] = await Promise.all([
      pool.query(`
        SELECT
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE role = 'candidate') as candidates,
          COUNT(*) FILTER (WHERE role = 'recruiter') as recruiters
        FROM users
      `),
      pool.query(`
        SELECT COUNT(DISTINCT user_id) as active_today
        FROM events
        WHERE created_at >= NOW() - INTERVAL '24 hours'
        AND user_id IS NOT NULL
      `).catch(() => ({ rows: [{ active_today: 0 }] })),
      pool.query(`
        SELECT
          COUNT(*) as total,
          COUNT(*) FILTER (WHERE status = 'completed') as completed,
          COUNT(*) FILTER (WHERE status = 'in-progress' OR status = 'pending') as active
        FROM interviews
      `),
      pool.query(`
        SELECT COUNT(*) as count
        FROM interviews
        WHERE created_at >= NOW() - INTERVAL '24 hours'
      `),
    ]);

    const users = usersResult.rows[0];
    const interviews = interviewsResult.rows[0];

    return {
      users: {
        total: parseInt(users.total, 10),
        candidates: parseInt(users.candidates, 10),
        recruiters: parseInt(users.recruiters, 10),
        activeToday: parseInt(activeResult.rows[0]?.active_today || 0, 10),
      },
      interviews: {
        total: parseInt(interviews.total, 10),
        completed: parseInt(interviews.completed, 10),
        active: parseInt(interviews.active, 10),
        today: parseInt(interviewsTodayResult.rows[0]?.count || 0, 10),
      },
    };
  } catch (err) {
    console.error('[metrics] User metrics error:', err.message);
    return { error: err.message };
  }
}

/**
 * Get all metrics in one call (for dashboard).
 */
async function getAllMetrics() {
  const [server, db, users] = await Promise.all([
    getServerMetrics(),
    getDatabaseMetrics(),
    getUserMetrics(),
  ]);

  return {
    timestamp: new Date().toISOString(),
    server,
    database: db,
    api: requestMetrics.getSummary(),
    users: users.users || {},
    interviews: users.interviews || {},
  };
}

/**
 * Express middleware to record request metrics.
 * Should be placed early in the middleware chain.
 */
function metricsMiddleware(req, res, next) {
  if (req.path === '/health' || !req.path.startsWith('/api')) {
    return next();
  }

  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    // Normalize path: replace IDs with :id
    const normalizedPath = req.path.replace(/\/\d+/g, '/:id');
    requestMetrics.record(req.method, normalizedPath, res.statusCode, duration);
  });
  next();
}

module.exports = {
  getAllMetrics,
  getServerMetrics,
  getDatabaseMetrics,
  getUserMetrics,
  requestMetrics,
  metricsMiddleware,
};

/**
 * OpenAI Token Budget Service
 *
 * Tracks OpenAI token usage across all modalities (LLM, TTS, ASR, Vision, Embedding).
 * When daily budget (100K tokens) is exhausted, signals the AI provider to skip OpenAI
 * and route directly to NIM providers.
 *
 * Token estimation:
 * - LLM: uses response.usage.total_tokens when available, estimates from text length otherwise
 * - TTS: ~1 token per 4 characters of input text
 * - ASR: ~1 token per second of audio (Whisper pricing model)
 * - Vision: ~85 tokens per image + prompt tokens
 * - Embedding: ~1 token per 4 characters
 */

const DAILY_BUDGET = parseInt(process.env.OPENAI_DAILY_TOKEN_BUDGET, 10) || 100000;

class TokenBudgetService {
  constructor() {
    this.dailyBudget = DAILY_BUDGET;
    this.tokensUsed = 0;
    this.budgetExhausted = false;
    this.currentDay = this._getUTCDay();
    this.history = [];         // Last 7 days of usage
    this.modalityBreakdown = { // Per-modality tracking
      llm: 0,
      tts: 0,
      asr: 0,
      vision: 0,
      embedding: 0,
      other: 0,
    };
    this.exhaustedAt = null;   // Timestamp when budget was exhausted
    this.resetAt = null;       // Next reset time

    this._updateResetTime();
    this._startMidnightReset();

    console.log(`[token-budget] Initialized. Daily budget: ${this.dailyBudget.toLocaleString()} tokens`);
  }

  _getUTCDay() {
    const now = new Date();
    return `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, '0')}-${String(now.getUTCDate()).padStart(2, '0')}`;
  }

  _updateResetTime() {
    const now = new Date();
    const tomorrow = new Date(Date.UTC(
      now.getUTCFullYear(),
      now.getUTCMonth(),
      now.getUTCDate() + 1,
      0, 0, 0, 0
    ));
    this.resetAt = tomorrow.toISOString();
  }

  _startMidnightReset() {
    // Check every 60 seconds if the day has changed
    this._resetInterval = setInterval(() => {
      const today = this._getUTCDay();
      if (today !== this.currentDay) {
        this._performReset(today);
      }
    }, 60 * 1000);
  }

  _performReset(newDay) {
    // Save yesterday's usage to history
    this.history.push({
      date: this.currentDay,
      tokensUsed: this.tokensUsed,
      budget: this.dailyBudget,
      breakdown: { ...this.modalityBreakdown },
      exhaustedAt: this.exhaustedAt,
    });

    // Keep only last 7 days
    if (this.history.length > 7) {
      this.history.shift();
    }

    // Reset counters
    const wasExhausted = this.budgetExhausted;
    this.tokensUsed = 0;
    this.budgetExhausted = false;
    this.exhaustedAt = null;
    this.currentDay = newDay;
    this.modalityBreakdown = { llm: 0, tts: 0, asr: 0, vision: 0, embedding: 0, other: 0 };
    this._updateResetTime();

    console.log(`[token-budget] Daily reset. New day: ${newDay}. Previous budget ${wasExhausted ? 'was exhausted' : 'had remaining tokens'}.`);
    if (wasExhausted) {
      console.log('[token-budget] OpenAI is now available again after budget reset.');
    }
  }

  /**
   * Record token usage for an OpenAI call.
   * @param {string} modality - 'llm', 'tts', 'asr', 'vision', 'embedding'
   * @param {number} tokens - Number of tokens used
   */
  recordUsage(modality, tokens) {
    // Check if day rolled over
    const today = this._getUTCDay();
    if (today !== this.currentDay) {
      this._performReset(today);
    }

    this.tokensUsed += tokens;
    const bucket = this.modalityBreakdown[modality] !== undefined ? modality : 'other';
    this.modalityBreakdown[bucket] += tokens;

    // Check if budget is now exhausted
    if (!this.budgetExhausted && this.tokensUsed >= this.dailyBudget) {
      this.budgetExhausted = true;
      this.exhaustedAt = new Date().toISOString();
      console.log(`[token-budget] BUDGET EXHAUSTED at ${this.tokensUsed.toLocaleString()} tokens. Routing to NIM providers.`);
      // Log to activity feed
      try {
        const { logBudgetExhausted } = require('./activity-logger');
        logBudgetExhausted(this.tokensUsed, this.dailyBudget);
      } catch (e) { /* activity logger not loaded yet */ }
    }
  }

  /**
   * Check if OpenAI should be skipped due to budget exhaustion.
   * @returns {boolean} true if OpenAI budget is exhausted
   */
  isOpenAIBudgetExhausted() {
    // Check if day rolled over
    const today = this._getUTCDay();
    if (today !== this.currentDay) {
      this._performReset(today);
    }
    return this.budgetExhausted;
  }

  /**
   * Estimate token count from text content.
   * Uses rough heuristic: ~4 chars per token for English text.
   */
  estimateTokensFromText(text) {
    if (!text) return 0;
    return Math.ceil(text.length / 4);
  }

  /**
   * Estimate tokens for a TTS request.
   * OpenAI charges ~1 token per 4 characters for TTS.
   */
  estimateTTSTokens(text) {
    if (!text) return 0;
    return Math.ceil(text.length / 4);
  }

  /**
   * Estimate tokens for an ASR request.
   * Whisper charges ~$0.006/min, roughly ~100 tokens per minute.
   * We estimate from audio buffer size: ~16KB per second at 16kHz mono.
   */
  estimateASRTokens(audioBufferSize) {
    if (!audioBufferSize) return 100; // Minimum estimate
    const estimatedSeconds = audioBufferSize / 16000;
    return Math.ceil(estimatedSeconds * (100 / 60)); // ~100 tokens per minute
  }

  /**
   * Estimate tokens for a vision request.
   * GPT-4o vision: ~85 tokens per low-detail image + prompt tokens.
   */
  estimateVisionTokens(imageCount, promptLength) {
    const imageTokens = (imageCount || 1) * 85;
    const promptTokens = Math.ceil((promptLength || 0) / 4);
    return imageTokens + promptTokens;
  }

  /**
   * Get current budget status for the admin dashboard.
   */
  getStatus() {
    return {
      dailyBudget: this.dailyBudget,
      tokensUsed: this.tokensUsed,
      tokensRemaining: Math.max(0, this.dailyBudget - this.tokensUsed),
      percentUsed: Math.min(100, Math.round((this.tokensUsed / this.dailyBudget) * 100 * 10) / 10),
      budgetExhausted: this.budgetExhausted,
      exhaustedAt: this.exhaustedAt,
      currentDay: this.currentDay,
      resetAt: this.resetAt,
      breakdown: { ...this.modalityBreakdown },
      history: [...this.history],
      routingStatus: this.budgetExhausted ? 'nim_only' : 'openai_primary',
    };
  }

  destroy() {
    if (this._resetInterval) {
      clearInterval(this._resetInterval);
    }
  }
}

// Singleton
const tokenBudget = new TokenBudgetService();
module.exports = tokenBudget;

